25	function DawShellInner({
26	  sessionStorage,
27	}: {
28	  sessionStorage: SessionStorage;
29	}): React.JSX.Element {
30	  const registry = useMemo(() => new CommandRegistry(), []);
31	  const shortcuts = useMemo(() => new ShortcutMap(), []);
32	  const pool = useMediaPool();
33	  const undoManager = sharedUndoManager;
34	  const { saveNow, recoveryWarnings } = useSessionPersistence(sessionStorage);
35	  const [dismissed, setDismissed] = useState(false);
36	  const [shortcutsOpen, setShortcutsOpen] = useState(false);
37	  const showRecovery = !dismissed && recoveryWarnings.length > 0;
38	
39	  const stableSaveNow = useCallback(() => saveNow(), [saveNow]);
40	
41	  useTransportShortcuts(registry, shortcuts);
42	  useSessionShortcuts(registry, shortcuts, undoManager, stableSaveNow);
43	
44	  useEffect(() => {
45	    registry.register({
46	      id: "app.shortcuts-legend",
