    ? `${styles["panel"]} ${styles["dragging"]}`
    : styles["panel"];

  return (
    <section
      data-testid="media-pool-panel"
      className={panelClass}
      {...handlers}
    >
      <div className={styles["header"]}>
        <span>MEDIA POOL</span>
